import { CaseStatus } from './case-status';
import { SavCase } from './sav-case';
import { AuditLogEntry, createAuditLog } from './audit-log';
import { canDeliverCase, isQCValidated } from './delivery-rules';
import { isQCComplete } from './qc-rules';
import { Role } from '../types';
import { getBlockingClaimsReasons } from './claims';

export interface TransitionResult {
  success: boolean;
  error?: string;
  updatedCase?: SavCase;
  auditLog?: AuditLogEntry;
}

/**
 * Standard allowed transitions for SAV workflow
 */
export const ALLOWED_TRANSITIONS: Record<CaseStatus, readonly CaseStatus[]> = {
  draft: ['received', 'cancelled'],
  received: ['diagnosis', 'cancelled'],
  diagnosis: ['waiting_parts', 'repair', 'cancelled'],
  waiting_parts: ['repair', 'cancelled'],
  repair: ['work_completed'],
  work_completed: ['quality_pending'],
  quality_pending: ['quality_approved', 'quality_rejected'],
  quality_rejected: ['quality_rework'],
  quality_rework: ['quality_pending'],
  quality_approved: ['ready_delivery'],
  ready_delivery: ['delivered'],
  delivered: ['closed'],
  closed: [],
  cancelled: [],
};

/**
 * Transitions a case to a new status while enforcing all domain constraints and permissions.
 */
export function transitionCase(
  caseObj: SavCase,
  targetStatus: CaseStatus,
  user: { id: string; role: Role }
): TransitionResult {
  // 1. Read-only users can never modify cases
  if (user.role === 'lecture-seule') {
    return { success: false, error: 'Read-only users cannot perform modifications.' };
  }

  // Delivered is forward-only: the only valid next state is closed.
  if (caseObj.status === 'delivered' && targetStatus !== 'closed') {
    return { success: false, error: 'Delivered cases cannot move backward in the workflow.' };
  }

  // 2. Role-workflow specific boundaries
  // - Technicians cannot validate or reject QC
  if ((targetStatus === 'quality_approved' || targetStatus === 'quality_rejected') && user.role === 'technicien') {
    return { success: false, error: 'Technicians cannot validate or reject QC.' };
  }
  // - Livraison cannot validate or reject QC
  if ((targetStatus === 'quality_approved' || targetStatus === 'quality_rejected') && user.role === 'livraison') {
    return { success: false, error: 'Livraison role cannot validate or reject QC.' };
  }
  // - Reception cannot close cases
  if (targetStatus === 'closed' && user.role === 'reception') {
    return { success: false, error: 'Reception role cannot close cases.' };
  }
  // - Chef Atelier cannot close cases
  if (targetStatus === 'closed' && user.role === 'chef-atelier') {
    return { success: false, error: 'Chef Atelier role cannot close cases.' };
  }
  // - Livraison cannot close cases
  if (targetStatus === 'closed' && user.role === 'livraison') {
    return { success: false, error: 'Livraison role cannot close cases.' };
  }

  let isExceptionalAdminAction = false;

  // 3. Protection of 'closed' and 'cancelled' states
  if (caseObj.status === 'closed' || caseObj.status === 'cancelled') {
    if (user.role === 'admin') {
      isExceptionalAdminAction = true;
    } else {
      return { success: false, error: `Cases in ${caseObj.status} status cannot be modified except by Admin.` };
    }
  }

  // 4. Late cancellation restrictions (repair and beyond)
  const isLateCancel = targetStatus === 'cancelled' &&
    !['draft', 'received', 'diagnosis', 'waiting_parts'].includes(caseObj.status);

  if (isLateCancel) {
    if (user.role === 'admin') {
      isExceptionalAdminAction = true;
    } else {
      return { success: false, error: `Cancellation from ${caseObj.status} status is forbidden except for Admin.` };
    }
  }

  // Claims validation checks
  const isEngagingAtelier = ['diagnosis', 'waiting_parts', 'repair'].includes(targetStatus);
  if (isEngagingAtelier && !isExceptionalAdminAction) {
    const blockingReasons = getBlockingClaimsReasons(caseObj.claims || [], caseObj.claimsOverridden);
    if (blockingReasons.length > 0) {
      return {
        success: false,
        error: 'Planification bloquée : accord expert/client manquant',
      };
    }
  }

  // 5. Standard transition check
  if (!isExceptionalAdminAction) {
    const allowed = ALLOWED_TRANSITIONS[caseObj.status] || [];
    if (!allowed.includes(targetStatus)) {
      return { success: false, error: `Invalid transition from ${caseObj.status} to ${targetStatus}.` };
    }
  }

  // - Chef Atelier authorized transitions restriction (run after standard and protection checks)
  if (user.role === 'chef-atelier' && !isExceptionalAdminAction) {
    const isAuthorized = (
      (caseObj.status === 'received' && targetStatus === 'diagnosis') ||
      (caseObj.status === 'diagnosis' && targetStatus === 'waiting_parts') ||
      (caseObj.status === 'diagnosis' && targetStatus === 'repair') ||
      (caseObj.status === 'waiting_parts' && targetStatus === 'repair') ||
      (caseObj.status === 'repair' && targetStatus === 'work_completed') ||
      (caseObj.status === 'quality_rejected' && targetStatus === 'quality_rework')
    );
    if (!isAuthorized) {
      return { success: false, error: `Chef Atelier role is not authorized to transition from ${caseObj.status} to ${targetStatus}.` };
    }
  }

  // - Technicien authorized transitions restriction (run after standard and protection checks)
  if (user.role === 'technicien' && !isExceptionalAdminAction) {
    if (caseObj.assignedTechnicianId !== user.id) {
      return { success: false, error: 'This dossier is not assigned to you.' };
    }

    const isAuthorized = (
      (caseObj.status === 'diagnosis' && targetStatus === 'repair') ||
      (caseObj.status === 'waiting_parts' && targetStatus === 'repair') ||
      (caseObj.status === 'repair' && targetStatus === 'work_completed')
    );
    if (!isAuthorized) {
      return { success: false, error: `Technician role is not authorized to transition from ${caseObj.status} to ${targetStatus}.` };
    }

    if (targetStatus === 'work_completed') {
      const tasks = caseObj.workshopTasks || [];
      if (tasks.length === 0) {
        return { success: false, error: 'Cannot complete work: no workshop tasks exist.' };
      }
      const hasUnfinishedTasks = tasks.some(t => t.status !== 'done');
      if (hasUnfinishedTasks) {
        return { success: false, error: 'Cannot complete work: some workshop tasks are not completed.' };
      }
    }
  }

  // - Quality Control (qualite/qc) authorized transitions restriction (run after standard and protection checks)
  if (user.role === 'qualite' && !isExceptionalAdminAction) {
    const isAuthorized = (
      (caseObj.status === 'work_completed' && targetStatus === 'quality_pending') ||
      (caseObj.status === 'quality_pending' && targetStatus === 'quality_approved') ||
      (caseObj.status === 'quality_pending' && targetStatus === 'quality_rejected') ||
      (caseObj.status === 'quality_rejected' && targetStatus === 'quality_rework') ||
      (caseObj.status === 'quality_rework' && targetStatus === 'quality_pending')
    );
    if (!isAuthorized) {
      return { success: false, error: `Quality Control role is not authorized to transition from ${caseObj.status} to ${targetStatus}.` };
    }

    if (targetStatus === 'quality_approved') {
      if (!isQCComplete(caseObj)) {
        return { success: false, error: 'Cannot approve Quality Control: not all required checklist items are checked.' };
      }
    }

    if (targetStatus === 'quality_rejected') {
      const reason = caseObj.qcRejectionReason;
      if (!reason || reason.trim() === '') {
        return { success: false, error: 'Rejection reason is required.' };
      }
    }

    if (targetStatus === 'quality_rework') {
      const reason = caseObj.qcReworkReason;
      if (!reason || reason.trim() === '') {
        return { success: false, error: 'Rework reason is required.' };
      }
    }
  }

  // - Restrict who can transition to QC statuses
  if (['quality_pending', 'quality_approved', 'quality_rejected'].includes(targetStatus) && !isExceptionalAdminAction) {
    if (user.role !== 'qualite') {
      return { success: false, error: `Only Quality Control role is authorized to transition to ${targetStatus}.` };
    }
  }

  if (targetStatus === 'quality_rework' && !isExceptionalAdminAction) {
    if (user.role !== 'qualite' && user.role !== 'chef-atelier') {
      return { success: false, error: `Only Quality Control or Chef Atelier roles are authorized to transition to ${targetStatus}.` };
    }
  }

  // - Restrict who can transition to delivery statuses
  if (['ready_delivery', 'delivered'].includes(targetStatus) && !isExceptionalAdminAction) {
    if (user.role !== 'livraison') {
      return { success: false, error: `Only Livraison role is authorized to transition to ${targetStatus}.` };
    }
  }

  // - Restrict who can transition to received status
  if (targetStatus === 'received' && !isExceptionalAdminAction) {
    if (user.role !== 'reception' && user.role !== 'admin') {
      return { success: false, error: `Only Reception role is authorized to transition to received.` };
    }
  }

  // - Restrict who can transition to closed status
  if (targetStatus === 'closed' && !isExceptionalAdminAction) {
    if (user.role !== 'directeur-sav' && user.role !== 'admin') {
      return { success: false, error: `Only SAV Director role is authorized to transition to closed.` };
    }
  }

  // - Restrict who can transition to workshop statuses
  if (['diagnosis', 'waiting_parts', 'repair'].includes(targetStatus) && !isExceptionalAdminAction) {
    if (user.role !== 'chef-atelier' && user.role !== 'technicien' && user.role !== 'admin') {
      return { success: false, error: `Only Chef Atelier or Technician roles are authorized to transition to ${targetStatus}.` };
    }
  }

  // - Restrict who can transition to work completed status
  if (targetStatus === 'work_completed' && !isExceptionalAdminAction) {
    if (user.role !== 'technicien' && user.role !== 'chef-atelier' && user.role !== 'admin') {
      return { success: false, error: `Only Technician or Chef Atelier roles are authorized to transition to work_completed.` };
    }
  }

  // - Livraison authorized transitions restriction
  if (user.role === 'livraison' && !isExceptionalAdminAction) {
    const isAuthorized = (
      (caseObj.status === 'quality_approved' && targetStatus === 'ready_delivery') ||
      (caseObj.status === 'ready_delivery' && targetStatus === 'delivered')
    );
    if (!isAuthorized) {
      return { success: false, error: `Livraison role is not authorized to transition from ${caseObj.status} to ${targetStatus}.` };
    }
  }

  // 6. Delivery checks
  if (targetStatus === 'ready_delivery' && !isExceptionalAdminAction) {
    if (!isQCValidated(caseObj)) {
      return { success: false, error: 'Cannot prepare delivery: QC is not approved/validated.' };
    }
  }

  if (targetStatus === 'delivered' && !isExceptionalAdminAction) {
    if (!caseObj.deliveryRecipientName || caseObj.deliveryRecipientName.trim() === '') {
      return { success: false, error: 'Cannot deliver case: Recipient name is required.' };
    }
    if (!caseObj.deliveryProofReference || caseObj.deliveryProofReference.trim() === '') {
      return { success: false, error: 'Cannot deliver case: Proof reference is required.' };
    }
    if (!canDeliverCase(caseObj)) {
      return { success: false, error: 'Cannot deliver case: QC checklist must be validated and status must be ready_delivery.' };
    }
  }

  // 7. Apply the transition
  const updatedCase: SavCase = {
    ...caseObj,
    status: targetStatus,
    updatedAt: new Date().toISOString(),
  };

  // Set timestamps for final states if not exceptional admin action bypass
  if (targetStatus === 'delivered') {
    updatedCase.deliveryDate = new Date().toISOString();
  } else if (targetStatus === 'closed') {
    updatedCase.closedDate = new Date().toISOString();
  }

  // 8. Generate Audit Log
  const actionType = isExceptionalAdminAction ? 'EXCEPTIONAL_ADMIN_ACTION' : 'STATUS_TRANSITION';
  const details = isExceptionalAdminAction
    ? `Exceptional Admin action: transitioned from ${caseObj.status} to ${targetStatus}`
    : `Status transitioned from ${caseObj.status} to ${targetStatus}`;

  const auditLog = createAuditLog(
    caseObj.id,
    user.id,
    user.role,
    actionType,
    caseObj.status,
    targetStatus,
    details
  );

  return {
    success: true,
    updatedCase,
    auditLog,
  };
}
